/**
 * Gallery items for CircularGallery — sourced from galleryManifest.json.
 *
 * Manifest is regenerated by scripts/generate-gallery-manifest.mjs on predev/prebuild.
 * To add images: place files in public/media/servicescards/ (exclude marquee.png), then restart dev.
 */
import manifest from "./galleryManifest.json";

function filenameToTitle(filename) {
  const base = filename.replace(/\.[^.]+$/, "");
  return `Security Service ${base}`;
}

/**
 * @returns {import('../components/ui/circular-gallery.jsx').GalleryItem[]}
 */
export function buildGalleryData() {
  return manifest.map(({ filename, url }) => {
    const title = filenameToTitle(filename);
    return {
      common: title,
      binomial: "Eagle Eye Watch",
      photo: {
        url,
        text: `${title} — Eagle Eye Watch security services in Bangalore`,
        by: "Eagle Eye Watch",
      },
    };
  });
}

export const galleryData = buildGalleryData();
